import { useState, useEffect, useRef } from "react";
import { sendChatMessage } from "../services/api";
import MedicalReportCard from "./MedicalReportCard";
import "./ChatBox.css";

function ChatBox() {
  const userId = localStorage.getItem("user_id");

  const [message, setMessage] = useState("");
  const [chat, setChat] = useState([
    { sender: "Doctor-AI", text: "Hello 🙂 I’m glad you reached out. What’s your name?" }
  ]);

  const [finalReport, setFinalReport] = useState("");
  const [pdfPath, setPdfPath] = useState("");
  const [loading, setLoading] = useState(false);

  const chatEndRef = useRef(null);

  useEffect(() => {
    chatEndRef.current?.scrollIntoView({ behavior: "smooth" });
  }, [chat, loading]);

  const sendMessage = async () => {
    if (!message.trim()) return;

    const userMsg = message;
    setMessage("");
    setChat(prev => [...prev, { sender: "You", text: userMsg }]);
    setLoading(true);

    try {
      const res = await sendChatMessage({
        user_id: userId,
        message: userMsg
      });

      const reply = res.data.reply;
      setChat(prev => [...prev, { sender: "Doctor-AI", text: reply }]);

      if (reply.startsWith("FINAL ASSESSMENT")) {
        setFinalReport(reply);
        setPdfPath(res.data.report_pdf);
      }

    } catch {
      setChat(prev => [...prev, { sender: "Doctor-AI", text: "Sorry 😔 Something went wrong." }]);
    }

    setLoading(false);
  };

  return (
    <div>
      <div className="chatbox-container">
        <div className="chat-messages">
          {chat.map((c, i) => (
            <div key={i} className={c.sender === "You" ? "chat-bubble user" : "chat-bubble doctor"}>
              <b>{c.sender}</b>
              <p>{c.text}</p>
            </div>
          ))}
          {loading && <div className="chat-bubble doctor">Doctor-AI is typing…</div>}
          <div ref={chatEndRef} />
        </div>

        <div className="chat-input">
          <input
            value={message}
            onChange={e => setMessage(e.target.value)}
            placeholder="Type your message…"
            onKeyDown={e => e.key === "Enter" && sendMessage()}
          />
          <button onClick={sendMessage}>Send ➤</button>
        </div>
      </div>

      {/* ✅ FINAL REPORT UI */}
      <MedicalReportCard reportText={finalReport} pdfPath={pdfPath} />
    </div>
  );
}

export default ChatBox;
